changeSet.sql:
ALTER TABLE public.species ADD COLUMN IF NOT EXISTS active boolean NOT NULL DEFAULT true;
ALTER TABLE public.species ADD COLUMN IF NOT EXISTS authoring_json jsonb;
ALTER TABLE public.species ADD COLUMN IF NOT EXISTS created_by uuid;
ALTER TABLE public.species ADD COLUMN IF NOT EXISTS updated_by uuid;

ALTER TABLE public.species ADD CONSTRAINT fk_species_created_by FOREIGN KEY (created_by) REFERENCES public.users(id) ON DELETE SET NULL;
ALTER TABLE public.species ADD CONSTRAINT fk_species_updated_by FOREIGN KEY (updated_by) REFERENCES public.users(id) ON DELETE SET NULL;

UPDATE public.species s SET created_by = hp.author_id, updated_by = hp.author_id
    FROM public.homebrew_packages hp WHERE s.homebrew_id = hp.id AND s.created_by IS NULL;
